INSERT OR IGNORE INTO dialect_map (dialect_name, category, standard_word, dialect_word, remark) VALUES ('广东话', '日常用语', '<think>The user wants translations from Mandarin (普通话) to Cantonese (粤语). Each line format: 【普通话', '粤语】. Don''t think, don''t explain, just output the translation lines. They gave a list of words/phrases.', '');
INSERT OR IGNORE INTO dialect_map (dialect_name, category, standard_word, dialect_word, remark) VALUES ('广东话', '日常用语', 'But perhaps they want the Cantonese spoken form transliteration: like "深" might be "深" (sam1). But they said translation "普通话', '粤语". That might mean: Provide the Mandarin phrase and then the Cantonese phrase (maybe in romanization or characters?). Usually "粤语" refers to the spoken language, but you can present in characters (since Cantonese uses characters mostly identical). However, Cantonese has some unique characters (like "咗", "嘅", "哋", "噶", "囖"?). Also the phrase "坏了" uses "壞咗". So need to incorporate those differences. So for each entry, we need to provide the Cantonese equivalent phrase, using appropriate Cantonese lexical forms.', '');
